-      cells() { gridderInit(x0Arg, y0Arg, x1Arg, y1Arg, ppCell); }
-
-  // Destructor
-  ~Gridder() {
-    for (unsigned int i = 0; i < cells.size(); i++) {
-      for (unsigned int j = 0; j < cells[i].size(); j++)
