-// open a serial port connection
-void Serial::open(const string& port, int rate) {
-  m_serialPort = ::open(port.c_str(), O_RDWR | O_NOCTTY | O_NDELAY);
-  if (m_serialPort==-1) {
-    cout << "Unable to open serial port" << endl;
