-// utility function to provide current system time (used below in
-// determining frame rate at which images are being processed)
-double tic() {
-  struct timeval t;
-  gettimeofday(&t, NULL);
-  return ((double)t.tv_sec + ((double)t.tv_usec)/1000000.);
-}
-
